const normalized = $node['Normalize Instagram Event'].json || {};
const tenantRows = Array.isArray($node['Get Tenant Settings'].json)
  ? $node['Get Tenant Settings'].json
  : ($node['Get Tenant Settings'].json ? [$node['Get Tenant Settings'].json] : []);
const tenantSettings = tenantRows.find((row) => row && row.tenant_id) || tenantRows[0] || {};

const threadPayload = $node['Get Thread Context'].json || $json || {};
const threadRows = Array.isArray(threadPayload.rows)
  ? threadPayload.rows
  : Array.isArray(threadPayload)
    ? threadPayload
    : Array.isArray($json)
      ? $json
      : [];

const messageText = String(normalized.message_text || '').trim();
const lowered = messageText.toLowerCase();

const askSignals = [
  'what', 'how', 'where', 'when', 'why', 'help', 'info', 'price',
  'support', 'can', 'tell me', 'please', 'document', 'guide', 'policy',
  'plan', 'cost', 'hours', 'status', '?',
];
const handoffSignals = [
  'human', 'agent', 'operator', 'manager', 'handover', 'escalate',
  'real person', 'support team', 'someone else',
];

let intent = 'other';
let intentConfidence = 0.42;
let intentReason = 'fallback_other';

if (handoffSignals.some((signal) => lowered.includes(signal))) {
  intent = 'human_handoff';
  intentConfidence = 0.98;
  intentReason = 'handoff_signal_match';
} else if (askSignals.some((signal) => lowered.includes(signal))) {
  intent = 'ask';
  intentConfidence = lowered.includes('?') ? 0.95 : 0.89;
  intentReason = 'ask_signal_match';
} else if (messageText.length > 260) {
  intent = 'ask';
  intentConfidence = 0.6;
  intentReason = 'long_message_fallback';
}

const recentContext = Array.isArray(threadRows)
  ? threadRows
      .filter((row) => row && typeof row === 'object')
      .slice(0, 4)
      .map((row) => ({
        role: row.role,
        intent: row.intent || null,
        content: row.content,
        confidence: row.confidence,
      }))
  : [];

return [{
  json: {
    ...normalized,
    tenant_settings: tenantSettings,
    tenant_style: tenantSettings.response_style || 'concise, practical, and polite',
    thread_context_rows: threadRows,
    thread_context_preview: recentContext,
    intent,
    intent_confidence: Number(intentConfidence.toFixed(2)),
    intent_source: intentReason,
    classified_at: new Date().toISOString(),
  },
}];

const source = $node['Classify Message Intent'].json || {};
const payload = $json || {};
const data = Array.isArray(payload.data) ? payload.data : [];
const embedding = data[0]?.embedding;

if (!Array.isArray(embedding) || embedding.length === 0) {
  throw new Error('No embedding returned by OpenAI.');
}

const fallbackModel = 'text-embedding-3-small';
const sourceModel = source.openai_embedding_model || source.tenant_settings?.embedding_model || source.tenant_settings?.openai_embedding_model;
const candidateModel = data[0]?.model || sourceModel || fallbackModel;

return [{
  json: {
    ...source,
    embedding,
    openai_embedding_model: candidateModel,
    openai_embedding_usage: data[0]?.usage || payload.usage || {},
    ask_stage: 'embedded',
    normalized_at: new Date().toISOString(),
  }
}];

