const source = $node['Parse Embedding'].json || {};
const rows = Array.isArray($json) ? $json : [];
const tenantSettings = source.tenant_settings || {};

function toNumber(value, fallback) {
  const parsed = Number(value);
  return Number.isFinite(parsed) ? parsed : fallback;
}

const threshold = toNumber(source.rag_confidence_threshold ?? tenantSettings.confidence_threshold ?? tenantSettings.rag_confidence_threshold, 0.30);
const minSimilarity = Math.max(0.05, Math.min(toNumber(source.rag_min_similarity ?? tenantSettings.rag_min_similarity, 0.10), 0.30));
const limit = Math.max(1, Math.min(Math.floor(toNumber(source.rag_match_count ?? tenantSettings.match_count ?? tenantSettings.supabase_match_count, 10)), 20));

const docs = rows
  .map((row) => ({
    id: row.id,
    tenant_id: row.tenant_id,
    source_type: row.source_type || row.metadata?.source_type || '',
    source_key: row.source_key || row.metadata?.source_key || row.metadata?.source || '',
    chunk_text: row.chunk_text || row.content || '',
    metadata: row.metadata || {},
    similarity: toNumber(row.similarity, 0),
  }))
  .filter((row) => row.id && row.chunk_text && row.similarity >= minSimilarity)
  .sort((a, b) => b.similarity - a.similarity)
  .slice(0, limit)
  .map((row, index) => ({ ...row, rank: index + 1 }));

const retrievalSimilarity = docs.length ? Math.max(...docs.map((doc) => doc.similarity || 0)) : 0;
const messageText = String(source.message_text || '');
const hasCyrillic = /[А-Яа-яЁё]/.test(messageText);
const hasCjk = /[\u3400-\u9FFF\uF900-\uFAFF]/u.test(messageText);
const customerLanguage = hasCyrillic ? 'Russian' : hasCjk ? 'Cantonese/Traditional Chinese' : 'English';
const preferredCurrency = /(hong\s*kong|\bhk\b|hk\$|香港|港|廣東話|广东话|粵語|粤语|cantonese)/i.test(messageText) || hasCjk ? 'HKD' : 'USD';
const salesIntent = /\b(price|pricing|cost|package|packages|offer|offers|service|services|sell|buy|quote|proposal|instagram|automation|dm|lead|leads|audit|workflow|crm|bot|chatbot|sales|business|website|payment|payments|content|marketplace|support|process|system)\b|цена|цены|прайс|стоим|сколько|пакет|пакеты|услуг|сервис|предлож|аудит|автоматизац|бот|инстаграм|телеграм|сайт|crm|црм|оплат|лид|лиды|продаж|контент|маркетплейс|бизнес|проблем|процесс|система|поддержк|что вы можете|чем помог/i.test(messageText);
const hardHandoff = /\b(human|operator|manager|escalate|complaint|refund|legal|lawyer|urgent|real person|human agent|live agent|support person)\b/i.test(messageText);
const salesContext = docs.some((doc) => {
  const haystack = [doc.source_key, doc.source_type, doc.chunk_text].join(' ').toLowerCase();
  return /private_bot_memory|company_identity|services?|offers?|fixed_price|price|pricing|quote|package|sales|playbook|qualification|scoping|dialogue|objection/.test(haystack);
});
const salesContextOverride = salesIntent && salesContext && retrievalSimilarity >= 0.28;
const answerableNearThreshold = docs.length > 0 && retrievalSimilarity >= Math.max(0.28, threshold - 0.12);

let decisionReason = 'answerable_confidence';
let escalateByConfidence = false;
if (hardHandoff) { decisionReason = 'explicit_handoff_request'; escalateByConfidence = true; }
else if (docs.length === 0) { decisionReason = 'no_retrieved_context'; escalateByConfidence = true; }
else if (salesContextOverride) { decisionReason = 'sales_context_override'; escalateByConfidence = false; }
else if (answerableNearThreshold) { decisionReason = 'near_threshold_with_context'; escalateByConfidence = false; }
else if (retrievalSimilarity < threshold) { decisionReason = 'low_rag_confidence'; escalateByConfidence = true; }

const brand = tenantSettings.brand_name || source.brand_name || 'Sell.Systems';
const style = tenantSettings.response_style || source.response_style || 'direct, practical, sales-oriented Instagram DM';
const escalationTarget = tenantSettings.escalation_target || source.escalation_target || 'human operator';
const threadRows = Array.isArray(source.thread_context_rows) ? source.thread_context_rows : [];

const retrievalContext = docs.length
  ? docs.map((doc) => '[#' + doc.rank + '] source=' + (doc.source_key || 'unknown_source') + ' similarity=' + doc.similarity.toFixed(3) + '\n' + doc.chunk_text).join('\n\n---\n\n')
  : 'No matching context found in Supabase vector store.';

const threadContextText = threadRows.length
  ? threadRows.slice(0, 6).map((row) => '- ' + (row.role || 'unknown') + ': ' + (row.intent || 'n/a') + ' | ' + (row.content || '')).join('\n')
  : 'No prior thread context available.';

return [{
  json: {
    ...source,
    retrieved_documents: docs,
    retrieved_document_ids: docs.map((doc) => doc.id),
    retrieval_similarity: Number(retrievalSimilarity.toFixed(4)),
    retrieval_count: docs.length,
    retrieval_context: retrievalContext,
    thread_context_text: threadContextText,
    escalation_target: escalationTarget,
    escalate_by_confidence: escalateByConfidence,
    decision_reason: decisionReason,
    sales_intent: salesIntent,
    sales_context: salesContext,
    customer_language: customerLanguage,
    preferred_currency: preferredCurrency,
    rag_threshold: threshold,
    rag_min_similarity: minSimilarity,
    rag_match_count: limit,
    prompt_system: 'Required output language: ' + customerLanguage + '. This overrides retrieved context language. ' + 'You are the official ' + brand + ' inbound sales assistant for Instagram DM. Your job is to turn inbound messages into qualified sales conversations and recommend the best next step. Use only retrieved company context for factual claims about services, packages, pricing, process, proof, and policies. If retrieved context contains services, packages, audits, quote logic, or pricing guidance, answer with those details instead of escalating. Treat every inbound interest as sales discovery: if the customer asks about automation, AI, bots, Instagram, Telegram, CRM, websites, payments, leads, content, marketplaces, operations, support, pricing, or business problems, connect it to relevant Sell.Systems offers from context, explain the practical outcome, recommend the smallest useful next step, and ask one specific qualifying question. If the user asks about prices, packages, services, costs, quotes, budgets, or what Sell.Systems offers, and retrieved context contains fixed prices, anchor prices, currency amounts, packages, product names, or offer tables, name the relevant amounts directly in the context currency before saying details may vary. For broad pricing questions, give a compact menu of the most relevant retrieved offers instead of a vague depends answer. If exact pricing is not present in retrieved context, say pricing depends on scope and ask one or two qualification questions. Escalate only for explicit human handoff requests, legal/refund/complaint issues, sensitive account-specific cases, or when no useful context exists. Use the same language as the latest customer message. Do not switch language because retrieved context is written in another language. Keep the reply concise, practical, and sales-oriented. Style: ' + style + '.',
    prompt_user: 'Required output language: ' + customerLanguage + '\n\nCustomer message:\n' + source.message_text + '\n\nRecent thread context:\n' + threadContextText + '\n\nRetrieved company context:\n' + retrievalContext + '\n\nDecision metadata: confidence=' + retrievalSimilarity.toFixed(3) + ', threshold=' + threshold.toFixed(3) + ', reason=' + decisionReason + '.',
  },
}];

const source = $json;
const reply = 'I will ask a human operator to review this and follow up. I will stay silent here until the operator resets the handoff marker.';
return [{
  json: {
    ...source,
    llm_answer: reply,
    llm_raw: { escalated: true, reason: source.decision_reason || 'escalation_required' },
    escalated: true,
    answer_confidence: source.retrieval_similarity || 0,
    model_name: 'handoff_rule',
    generated_at: new Date().toISOString()
  }
}];

