const envelope = $json || {};
const query = envelope.query || {};
const expectedToken = $env["IG_WEBHOOK_VERIFY_TOKEN"];
const isValid = query['hub.mode'] === 'subscribe' && query['hub.verify_token'] === expectedToken;
return {
  json: {
    response_body: isValid ? String(query['hub.challenge'] || '') : 'Invalid hub.verify_token',
    response_code: isValid ? 200 : 403,
  },
};

const source = $node['Parse Reply'].json || $json || {};
return [{
  json: {
    ...source,
    delivery_status: 'dry_run',
    delivery_skipped: true,
    delivery_reason: 'IG_ACCESS_TOKEN and IG_INSTAGRAM_BUSINESS_ACCOUNT_ID are required for live Instagram delivery.',
    delivery_provider: 'instagram_messaging_api',
    delivery_at: new Date().toISOString()
  }
}];

let source = $json || {};
try {
  if (!source.llm_answer && $node['Build Escalation Reply'].json?.llm_answer) {
    source = $node['Build Escalation Reply'].json;
  }
} catch (error) {}
try {
  if (!source.llm_answer && $node['Build Handoff Reply'].json?.llm_answer) {
    source = $node['Build Handoff Reply'].json;
  }
} catch (error) {}
return [{
  json: {
    ...source,
    delivery_status: 'dry_run',
    delivery_skipped: true,
    delivery_reason: 'IG_ACCESS_TOKEN and IG_INSTAGRAM_BUSINESS_ACCOUNT_ID are required for live Instagram delivery.',
    delivery_provider: 'instagram_messaging_api',
    delivery_at: new Date().toISOString()
  }
}];

const source = $node['Handle Other Messages'].json || $json || {};
return [{
  json: {
    ...source,
    delivery_status: 'dry_run',
    delivery_skipped: true,
    delivery_reason: 'IG_ACCESS_TOKEN and IG_INSTAGRAM_BUSINESS_ACCOUNT_ID are required for live Instagram delivery.',
    delivery_provider: 'instagram_messaging_api',
    delivery_at: new Date().toISOString()
  }
}];
